"use client";

/**
 * Opener for the `smartCodeEditorWindow` overlay.
 *
 * - `useOpenSmartCodeEditorWindow()` — imperative hook. Call to open with typed options;
 *   returns a handle with a `close()` method.
 * - `<SmartCodeEditorWindowController />` — declarative wrapper. Mount to open,
 *   unmount to close. Equivalent ergonomics to rendering a normal component.
 *
 * Generated by scripts/generate-overlay-controller.ts (`openers` mode).
 * Hand-edit freely after the initial seed; the script will not re-emit a
 * file that already exists unless invoked with --force.
 */

import { useCallback, useEffect } from "react";
import { useAppDispatch } from "@/lib/redux/hooks";
import { closeOverlay, openOverlay } from "@/lib/redux/slices/overlaySlice";

const OVERLAY_ID = "smartCodeEditorWindow" as const;

export interface OpenSmartCodeEditorWindowOptions {
  /** Optional stable instance id. Omit to spawn a fresh instance. */
  instanceId?: string;
  windowInstanceId: string;
  callbackGroupId?: string | null;
  /** TODO: tighten to `CodeEditorAgentConfig[]` once that type is imported. */
  agents: unknown;
  defaultPickerAgentId?: string;
  initialCode?: string;
  language?: string;
  /** TODO: tighten to `CodeFile[]` once that type is imported. */
  files?: unknown;
  initialActiveFilePath?: string;
  filePath?: string;
  selection?: string;
  diagnostics?: string;
  workspaceName?: string;
  workspaceFolders?: string;
  gitBranch?: string;
  gitStatus?: string;
  agentSkills?: string;
  title?: string | null;
}

export interface SmartCodeEditorWindowHandle {
  instanceId: string;
  close: () => void;
}

export function useOpenSmartCodeEditorWindow() {
  const dispatch = useAppDispatch();
  return useCallback(
    (opts: OpenSmartCodeEditorWindowOptions): SmartCodeEditorWindowHandle => {
      const instanceId = opts.instanceId ?? `smartCodeEditorWindow-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      dispatch(
        openOverlay({
          overlayId: OVERLAY_ID,
          instanceId,
          data: {
            windowInstanceId: opts.windowInstanceId,
            callbackGroupId: opts.callbackGroupId,
            agents: opts.agents,
            defaultPickerAgentId: opts.defaultPickerAgentId,
            initialCode: opts.initialCode,
            language: opts.language,
            files: opts.files,
            initialActiveFilePath: opts.initialActiveFilePath,
            filePath: opts.filePath,
            selection: opts.selection,
            diagnostics: opts.diagnostics,
            workspaceName: opts.workspaceName,
            workspaceFolders: opts.workspaceFolders,
            gitBranch: opts.gitBranch,
            gitStatus: opts.gitStatus,
            agentSkills: opts.agentSkills,
            title: opts.title,
          },
        }),
      );
      return {
        instanceId,
        close: () => dispatch(closeOverlay({ overlayId: OVERLAY_ID, instanceId })),
      };
    },
    [dispatch],
  );
}

/**
 * Declarative form. Renders nothing visible; opens the overlay on mount,
 * closes it on unmount. Use this when a caller wants to express overlay
 * state declaratively (the way they'd render a normal component).
 */
export function SmartCodeEditorWindowController(props: OpenSmartCodeEditorWindowOptions): null {
  const open = useOpenSmartCodeEditorWindow();
  useEffect(() => {
    const handle = open(props);
    return () => handle.close();
  }, [open, props.windowInstanceId, props.callbackGroupId, props.agents, props.defaultPickerAgentId, props.initialCode, props.language, props.files, props.initialActiveFilePath, props.filePath, props.selection, props.diagnostics, props.workspaceName, props.workspaceFolders, props.gitBranch, props.gitStatus, props.agentSkills, props.title]);
  return null;
}
